import {
  chmodSync,
  existsSync,
  lstatSync,
  mkdirSync,
  readFileSync,
  writeFileSync,
} from "node:fs";
import { spawnSync } from "node:child_process";
import path from "node:path";
import { fileURLToPath } from "node:url";

const scriptPath = fileURLToPath(import.meta.url);
const repoRoot = path.resolve(path.dirname(scriptPath), "..", "..");

export const DEFAULT_HTTP_FIXTURE_DIR = path.join(
  repoRoot,
  "e2e",
  ".generated",
  "http",
);

const GENERATED_MARKER =
  "Generated by scripts/ci/e2e-http-fixtures.mjs for disposable local/CI testing.";

const fixturePaths = (outputDir) => ({
  outputDir,
  nginxConfig: path.join(outputDir, "nginx.conf"),
  htpasswd: path.join(outputDir, ".htpasswd"),
  sslDir: path.join(outputDir, "ssl"),
  certificate: path.join(outputDir, "ssl", "server.crt"),
  privateKey: path.join(outputDir, "ssl", "server.key"),
});

const runOpenSsl = (args, { input } = {}) => {
  const executable = process.env.OPENSSL_BIN || "openssl";
  const result = spawnSync(executable, args, {
    encoding: "utf8",
    input,
    windowsHide: true,
  });
  if (result.error) {
    throw new Error(
      `[e2e-http-fixtures] OpenSSL is required to prepare and validate the disposable TLS fixture: ${result.error.message}`,
    );
  }
  if (result.status !== 0) {
    const detail =
      result.stderr.trim() || result.stdout.trim() || "unknown error";
    throw new Error(`[e2e-http-fixtures] OpenSSL failed: ${detail}`);
  }
  return result.stdout.trim();
};

const requireRegularFile = (label, filePath) => {
  if (!existsSync(filePath)) {
    throw new Error(
      `[e2e-http-fixtures] Missing required ${label}: ${filePath}. Run \`node scripts/ci/e2e-http-fixtures.mjs prepare\` before Docker Compose.`,
    );
  }
  const stat = lstatSync(filePath);
  if (!stat.isFile()) {
    throw new Error(
      `[e2e-http-fixtures] Required ${label} must be a regular file, but found another filesystem entry: ${filePath}`,
    );
  }
  if (stat.size === 0) {
    throw new Error(
      `[e2e-http-fixtures] Required ${label} is empty: ${filePath}`,
    );
  }
};

const requireWritableFileTarget = (label, filePath) => {
  if (existsSync(filePath) && !lstatSync(filePath).isFile()) {
    throw new Error(
      `[e2e-http-fixtures] Cannot prepare ${label}; expected a file path but found another filesystem entry: ${filePath}`,
    );
  }
};

const ensureDirectory = (label, directoryPath) => {
  if (existsSync(directoryPath) && !lstatSync(directoryPath).isDirectory()) {
    throw new Error(
      `[e2e-http-fixtures] Cannot prepare ${label}; expected a directory path but found another filesystem entry: ${directoryPath}`,
    );
  }
  mkdirSync(directoryPath, { recursive: true });
};

const nginxConfig = `# ${GENERATED_MARKER}
server {
    listen 80 default_server;
    server_name localhost;

    location = /health {
        access_log off;
        default_type application/json;
        return 200 '{"status":"ok"}';
    }

    location / {
        auth_basic "sortOfRemoteNG disposable E2E fixture";
        auth_basic_user_file /etc/nginx/.htpasswd;
        root /usr/share/nginx/html;
        index index.html;
    }
}

server {
    listen 443 ssl default_server;
    server_name localhost;

    ssl_certificate /etc/nginx/ssl/server.crt;
    ssl_certificate_key /etc/nginx/ssl/server.key;
    ssl_protocols TLSv1.2 TLSv1.3;

    location = /health {
        access_log off;
        default_type application/json;
        return 200 '{"status":"ok"}';
    }

    location / {
        auth_basic "sortOfRemoteNG disposable E2E fixture";
        auth_basic_user_file /etc/nginx/.htpasswd;
        root /usr/share/nginx/html;
        index index.html;
    }
}
`;

export function prepareHttpFixtures({
  outputDir = DEFAULT_HTTP_FIXTURE_DIR,
  username = process.env.E2E_HTTP_USER || "testuser",
  password = process.env.E2E_HTTP_PASSWORD || "testpass",
} = {}) {
  if (!username || /[:\r\n]/u.test(username)) {
    throw new Error(
      "[e2e-http-fixtures] E2E_HTTP_USER must be non-empty and cannot contain a colon or newline.",
    );
  }
  if (!password || /[\r\n]/u.test(password)) {
    throw new Error(
      "[e2e-http-fixtures] E2E_HTTP_PASSWORD must be non-empty and cannot contain a newline.",
    );
  }

  const paths = fixturePaths(path.resolve(outputDir));
  ensureDirectory("fixture directory", paths.outputDir);
  ensureDirectory("TLS fixture directory", paths.sslDir);
  requireWritableFileTarget("nginx configuration", paths.nginxConfig);
  requireWritableFileTarget("HTTP basic-auth file", paths.htpasswd);
  requireWritableFileTarget("TLS certificate", paths.certificate);
  requireWritableFileTarget("TLS private key", paths.privateKey);

  const passwordHash = runOpenSsl(
    ["passwd", "-apr1", "-salt", "sorng123", "-stdin"],
    { input: `${password}\n` },
  );
  writeFileSync(paths.nginxConfig, nginxConfig, "utf8");
  writeFileSync(paths.htpasswd, `${username}:${passwordHash}\n`, "utf8");

  runOpenSsl([
    "req",
    "-x509",
    "-newkey",
    "rsa:2048",
    "-sha256",
    "-nodes",
    "-keyout",
    paths.privateKey,
    "-out",
    paths.certificate,
    "-days",
    "2",
    "-set_serial",
    "1",
    "-subj",
    "/CN=sortofremoteng-e2e.invalid",
    "-addext",
    "subjectAltName=DNS:localhost,IP:127.0.0.1",
  ]);

  if (process.platform !== "win32") {
    chmodSync(paths.nginxConfig, 0o644);
    chmodSync(paths.htpasswd, 0o644);
    chmodSync(paths.certificate, 0o644);
    chmodSync(paths.privateKey, 0o600);
  }

  validateHttpFixtures({ outputDir: paths.outputDir });
  return paths;
}

export function validateHttpFixtures({
  outputDir = DEFAULT_HTTP_FIXTURE_DIR,
} = {}) {
  const paths = fixturePaths(path.resolve(outputDir));
  requireRegularFile("nginx configuration", paths.nginxConfig);
  requireRegularFile("HTTP basic-auth file", paths.htpasswd);
  requireRegularFile("TLS certificate", paths.certificate);
  requireRegularFile("TLS private key", paths.privateKey);

  const config = readFileSync(paths.nginxConfig, "utf8");
  if (
    !config.includes(GENERATED_MARKER) ||
    !config.includes("listen 443 ssl") ||
    !config.includes("location = /health")
  ) {
    throw new Error(
      `[e2e-http-fixtures] Nginx fixture is stale or incomplete: ${paths.nginxConfig}`,
    );
  }

  const credentials = readFileSync(paths.htpasswd, "utf8").trim();
  if (!/^[^:\r\n]+:\$apr1\$[^\r\n]+$/u.test(credentials)) {
    throw new Error(
      `[e2e-http-fixtures] HTTP basic-auth fixture is malformed: ${paths.htpasswd}`,
    );
  }

  const certificatePublicKey = runOpenSsl([
    "x509",
    "-in",
    paths.certificate,
    "-pubkey",
    "-noout",
  ]);
  const privatePublicKey = runOpenSsl([
    "pkey",
    "-in",
    paths.privateKey,
    "-pubout",
  ]);
  if (certificatePublicKey !== privatePublicKey) {
    throw new Error(
      "[e2e-http-fixtures] Disposable TLS certificate and private key do not match.",
    );
  }

  return paths;
}

const isCli =
  process.argv[1] && path.resolve(process.argv[1]) === path.resolve(scriptPath);
if (isCli) {
  const command = process.argv[2] || "validate";
  const outputDir = process.argv[3] || DEFAULT_HTTP_FIXTURE_DIR;
  try {
    if (command === "prepare") {
      const paths = prepareHttpFixtures({ outputDir });
      console.log(
        `[e2e-http-fixtures] Prepared disposable fixtures in ${paths.outputDir}`,
      );
    } else if (command === "validate") {
      const paths = validateHttpFixtures({ outputDir });
      console.log(
        `[e2e-http-fixtures] Validated disposable fixtures in ${paths.outputDir}`,
      );
    } else {
      throw new Error(
        `[e2e-http-fixtures] Unknown command '${command}'. Expected 'prepare' or 'validate'.`,
      );
    }
  } catch (error) {
    console.error(error instanceof Error ? error.message : String(error));
    process.exitCode = 1;
  }
}
